def get_field(item, name):
    if isinstance(item, dict):
        return item.get(name)
    return getattr(item, name)

def total_quantity(items):
    return sum(get_field(item, 'quantity') for item in items)


def low_stock_names(items, threshold):
    return [get_field(item, 'name') for item in items if get_field(item, 'quantity') <= threshold]

print(total_quantity([{'quantity': 4}, {'quantity': 0}, {'quantity': 2}]))
print(', '.join(low_stock_names([{'name': 'Notebook', 'quantity': 4}, {'name': 'Marker', 'quantity': 0}, {'name': 'Tape', 'quantity': 2}], 2)))

