def get_field(item, name):
    if isinstance(item, dict):
        return item.get(name)
    return getattr(item, name)

def build_summary(items, threshold):
    total = sum(get_field(item, 'quantity') for item in items)
    low = [get_field(item, 'name') for item in items if get_field(item, 'quantity') <= threshold]
    in_stock = sum(1 for item in items if get_field(item, 'quantity') > 0)
    return {
        'total_quantity': total,
        'low_stock_names': low,
        'in_stock_count': in_stock,
    }

summary = build_summary([
    {'name': 'Notebook', 'quantity': 4},
    {'name': 'Marker', 'quantity': 3},
    {'name': 'Tape', 'quantity': 2},
], 2)
print(summary['total_quantity'])
print(summary['low_stock_names'])
print(summary['in_stock_count'])

